{
  "title": "Quick Garlic Butter Shrimp Pasta with White Beans",
  "description": "A quick and flavorful pasta dish featuring succulent shrimp, creamy white beans, and a rich garlic butter sauce, perfect for a weeknight meal.",
  "servings": 4,
  "prep_time_min": 10,
  "cook_time_min": 20,
  "difficulty": "intermediate",
  "ingredients": [
    {
      "name": "Spaghetti or Linguine",
      "quantity": 12,
      "unit": "ounce",
      "prep": null
    },
    {
      "name": "Shrimp",
      "quantity": 1,
      "unit": "lb",
      "prep": "peeled, deveined, tails on or off"
    },
    {
      "name": "Canned White Beans",
      "quantity": 15,
      "unit": "ounce",
      "prep": "drained and rinsed"
    },
    {
      "name": "Unsalted Butter",
      "quantity": 4,
      "unit": "tablespoon",
      "prep": null
    },
    {
      "name": "Olive Oil",
      "quantity": 2,
      "unit": "tablespoon",
      "prep": null
    },
    {
      "name": "Garlic",
      "quantity": 4,
      "unit": "clove",
      "prep": "minced"
    },
    {
      "name": "Red Pepper Flakes",
      "quantity": 0.5,
      "unit": "teaspoon",
      "prep": null
    },
    {
      "name": "Lemon",
      "quantity": 1,
      "unit": null,
      "prep": "juiced"
    },
    {
      "name": "Fresh Parsley",
      "quantity": 0.25,
      "unit": "cup",
      "prep": "chopped"
    },
    {
      "name": "Salt",
      "quantity": 0.5,
      "unit": "teaspoon",
      "prep": "or to taste"
    },
    {
      "name": "Black Pepper",
      "quantity": 0.25,
      "unit": "teaspoon",
      "prep": "freshly ground"
    }
  ],
  "steps": [
    {
      "text": "Cook pasta according to package directions in a large pot of generously salted water. Before draining, reserve 1 cup of pasta water."
    },
    {
      "text": "While the pasta cooks, pat the shrimp dry with paper towels and season with 1/4 teaspoon salt and 1/4 teaspoon black pepper."
    },
    {
      "text": "In a large skillet, melt the butter with the olive oil over medium heat. Add the minced garlic and red pepper flakes, and cook for 1 minute until fragrant, being careful not to burn the garlic."
    },
    {
      "text": "Add the seasoned shrimp to the skillet and cook for 2-3 minutes per side, until pink and opaque. Do not overcook."
    },
    {
      "text": "Add the drained and rinsed white beans to the skillet with the shrimp, stirring gently to combine and heat through for 1-2 minutes."
    },
    {
      "text": "Drain the cooked pasta and add it directly to the skillet with the shrimp and beans. Toss everything together, adding 1/2 cup of the reserved pasta water to create a light sauce. Add more pasta water, a tablespoon at a time, if needed to reach your desired consistency."
    },
    {
      "text": "Stir in the fresh lemon juice and chopped parsley. Taste and adjust seasoning with additional salt and pepper if necessary."
    },
    {
      "text": "Serve immediately, garnished with extra fresh parsley if desired."
    }
  ],
  "chefTips": [
    "To prevent rubbery shrimp, cook them quickly over medium-high heat until they just turn pink and opaque. They will continue to cook slightly from residual heat.",
    "The starchy pasta water is essential for creating a cohesive sauce that clings to the pasta. Don't skip reserving it!",
    "Rinsing canned beans thoroughly removes excess sodium and any canning liquid, ensuring a cleaner flavor in your dish."
  ]
}
